use serde::Serialize;

use crate::attention_closure_lift::{
    attention_closure_optimization_policy, attention_closure_state, estimate_closure_saved_work,
    AttentionClosureWorkload,
};
use crate::karmic_attention_optimizer::KARMIC_MESH_RESIDUAL_VANISHES_THEOREM;

pub const ATTENTION_CLOSURE_BENCHMARK_LABEL: &str = "attention_closure_benchmark";
pub const ATTENTION_CLOSURE_BENCHMARK_CERTIFICATE_VERSION: &str =
    "attention-closure-optimizer-admission/v1";

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct AttentionClosureBenchmarkConfig {
    pub heads: usize,
    pub coupling: usize,
    pub observer_resolution: usize,
    pub residue_threshold: usize,
    pub hidden_dim: usize,
    pub batch_size: usize,
    pub layer_count: usize,
    pub standing_count: usize,
    pub requested_speculative_depth: usize,
    pub speculative_candidates: usize,
    pub head_prune_candidates: usize,
    pub head_dim: usize,
}

impl Default for AttentionClosureBenchmarkConfig {
    fn default() -> Self {
        Self {
            heads: 8,
            coupling: 0,
            observer_resolution: 12,
            residue_threshold: 1,
            hidden_dim: 5_376,
            batch_size: 2,
            layer_count: 34,
            standing_count: 1_612,
            requested_speculative_depth: 8,
            speculative_candidates: 16,
            head_prune_candidates: 8,
            head_dim: 672,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
#[serde(rename_all = "camelCase")]
pub struct AttentionClosureBenchmarkReport {
    pub label: &'static str,
    pub certificate_version: &'static str,
    pub heads: usize,
    pub coupling: usize,
    pub observer_resolution: usize,
    pub source_resolution: usize,
    pub head_trace: Vec<usize>,
    pub state: String,
    pub policy: &'static str,
    pub theorem_lineage: Vec<&'static str>,
    pub preserve_heads: bool,
    pub allow_head_pruning: bool,
    pub allow_speculative_decode: bool,
    pub allow_standing_wave_compression: bool,
    pub route_action: String,
    pub speculative_depth_limit: usize,
    pub baseline_optimizer_units: usize,
    pub gated_optimizer_units: usize,
    pub avoided_optimizer_units: usize,
    pub avoided_compress_decompress_units: usize,
    pub avoided_speculative_units: usize,
    pub preserved_head_prune_units: usize,
    pub full_route_bytes_when_lifted: usize,
    pub compressed_route_bytes_if_stable: usize,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub karmic_regulator: Option<KarmicRegulatorWitness>,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
#[serde(rename_all = "camelCase")]
pub struct KarmicRegulatorWitness {
    pub theorem_lineage: Vec<&'static str>,
    pub golden_discriminant: i64,
}

pub fn build_attention_closure_benchmark_report(
    config: AttentionClosureBenchmarkConfig,
) -> AttentionClosureBenchmarkReport {
    let state = attention_closure_state(config.heads, config.coupling, config.observer_resolution);
    let policy = attention_closure_optimization_policy(
        state.clone(),
        config.residue_threshold,
        config.requested_speculative_depth,
    );
    let estimate = estimate_closure_saved_work(
        &policy,
        AttentionClosureWorkload {
            hidden_dim: config.hidden_dim,
            batch_size: config.batch_size,
            layer_count: config.layer_count,
            standing_count: config.standing_count,
            requested_speculative_depth: config.requested_speculative_depth,
            speculative_candidates: config.speculative_candidates,
            head_prune_candidates: config.head_prune_candidates,
            head_dim: config.head_dim,
        },
    );

    AttentionClosureBenchmarkReport {
        label: ATTENTION_CLOSURE_BENCHMARK_LABEL,
        certificate_version: ATTENTION_CLOSURE_BENCHMARK_CERTIFICATE_VERSION,
        heads: state.heads,
        coupling: config.coupling,
        observer_resolution: state.observer_resolution,
        source_resolution: state.source_resolution,
        head_trace: state.head_trace,
        state: format!("{:?}", state.kind),
        policy: policy.telemetry_label,
        theorem_lineage: policy.theorem_lineage.to_vec(),
        preserve_heads: policy.preserve_heads,
        allow_head_pruning: policy.allow_head_pruning,
        allow_speculative_decode: policy.allow_speculative_decode,
        allow_standing_wave_compression: policy.allow_standing_wave_compression,
        route_action: format!("{:?}", policy.route_action),
        speculative_depth_limit: policy.speculative_depth_limit,
        baseline_optimizer_units: estimate.baseline_optimizer_units,
        gated_optimizer_units: estimate.gated_optimizer_units,
        avoided_optimizer_units: estimate.avoided_optimizer_units,
        avoided_compress_decompress_units: estimate.avoided_compress_decompress_units,
        avoided_speculative_units: estimate.avoided_speculative_units,
        preserved_head_prune_units: estimate.preserved_head_prune_units,
        full_route_bytes_when_lifted: estimate.full_route_bytes_when_lifted,
        compressed_route_bytes_if_stable: estimate.compressed_route_bytes_if_stable,
        karmic_regulator: if policy.allow_head_pruning {
            Some(KarmicRegulatorWitness {
                theorem_lineage: vec![KARMIC_MESH_RESIDUAL_VANISHES_THEOREM],
                golden_discriminant: crate::karmic_attention_optimizer::GOLDEN_DISCRIMINANT,
            })
        } else {
            None
        },
    }
}

pub fn attention_closure_benchmark_json_pretty(
    config: AttentionClosureBenchmarkConfig,
) -> Result<String, serde_json::Error> {
    serde_json::to_string_pretty(&build_attention_closure_benchmark_report(config))
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::attention_closure_lift::AEON_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE;

    #[test]
    fn default_report_is_aeon_optimizer_admission_certificate() {
        let report =
            build_attention_closure_benchmark_report(AttentionClosureBenchmarkConfig::default());

        assert_eq!(report.label, ATTENTION_CLOSURE_BENCHMARK_LABEL);
        assert_eq!(
            report.certificate_version,
            ATTENTION_CLOSURE_BENCHMARK_CERTIFICATE_VERSION
        );
        assert_eq!(report.heads, 8);
        assert_eq!(report.observer_resolution, 12);
        assert_eq!(report.source_resolution, 24);
        assert_eq!(report.head_trace, vec![3, 6, 9, 0, 3, 6, 9, 0]);
        assert_eq!(report.state, "AliasedNoise");
        assert_eq!(report.policy, "attention_closure_lift_required");
        assert_eq!(
            report.theorem_lineage,
            AEON_EIGHT_HEAD_OPTIMIZER_THEOREM_LINEAGE.to_vec()
        );
        assert!(report.preserve_heads);
        assert!(!report.allow_head_pruning);
        assert!(!report.allow_speculative_decode);
        assert!(!report.allow_standing_wave_compression);
        assert_eq!(report.route_action, "LiftResolution");
        assert_eq!(report.speculative_depth_limit, 1);
        assert_eq!(report.gated_optimizer_units, 0);
        assert_eq!(
            report.avoided_optimizer_units,
            report.baseline_optimizer_units
        );
        assert!(report.karmic_regulator.is_none());
    }

    #[test]
    fn pretty_json_uses_forge_certificate_field_names() {
        let json =
            attention_closure_benchmark_json_pretty(AttentionClosureBenchmarkConfig::default())
                .expect("serialize report");

        assert!(json.contains("\"certificateVersion\""));
        assert!(json.contains("\"theoremLineage\""));
        assert!(json.contains("\"routeAction\""));
        assert!(!json.contains("certificate_version"));
    }

    #[test]
    fn lifted_closure_report_includes_karmic_regulator_witness() {
        let report = build_attention_closure_benchmark_report(AttentionClosureBenchmarkConfig {
            observer_resolution: 24,
            ..AttentionClosureBenchmarkConfig::default()
        });

        assert!(report.allow_head_pruning);
        let witness = report
            .karmic_regulator
            .as_ref()
            .expect("karmic regulator witness when pruning is admitted");
        assert_eq!(
            witness.theorem_lineage,
            vec![KARMIC_MESH_RESIDUAL_VANISHES_THEOREM]
        );
        assert_eq!(
            witness.golden_discriminant,
            crate::karmic_attention_optimizer::GOLDEN_DISCRIMINANT
        );
    }
}
